// src/features/lamaran/FavoriteService.js
import React, { useState, useEffect, useContext } from 'react';
import api from '../../services/api';
import { ThemeContext } from '../../context/ThemeContext';

const FavoriteService = ({ jobId }) => {
    const { theme } = useContext(ThemeContext);
    const isDark = theme === 'dark';
    const [isFavorited, setIsFavorited] = useState(false);
    const [isLoading, setIsLoading] = useState(false);

    // Cek apakah sudah difavoritkan saat komponen mount
    useEffect(() => {
        const checkFavorite = async () => {
            if (!jobId) return;

            // Cek apakah user sudah login
            const token = localStorage.getItem('token');
            if (!token) {
                console.log('User belum login, tidak bisa cek favorit');
                setIsFavorited(false);
                return;
            }

            try {
                console.log('Checking favorite for job:', jobId);
                console.log('Token:', token ? 'Ada' : 'Tidak ada');

                const response = await api.get(`/favorit/cek/${jobId}`);
                console.log('Check favorite response:', response.data);
                setIsFavorited(response.data.isFavorited);
            } catch (err) {
                console.error('Gagal cek favorit:', err.response?.status, err.response?.data);
                // Jika error 401, user mungkin belum login atau token invalid
                if (err.response?.status === 401) {
                    console.log('User tidak terautentikasi');
                    setIsFavorited(false);
                } else {
                    setIsFavorited(false);
                }
            }
        };
        checkFavorite();
    }, [jobId]);

    const toggleFavorite = async () => {
        if (isLoading) return;

        // Cek apakah user sudah login
        const token = localStorage.getItem('token');
        if (!token) {
            alert('ŌÜĀ’ĖÅ Silakan login terlebih dahulu untuk menyimpan favorit!');
            window.location.href = '/login';
            return;
        }

        setIsLoading(true);

        try {
            if (isFavorited) {
                // Hapus dari favorit
                console.log('Menghapus favorit:', jobId);
                const response = await api.delete(`/favorit/${jobId}`);
                console.log('Delete response:', response.data);
                setIsFavorited(false);
                alert('ŌŁÉ Lowongan dihapus dari favorit');
            } else {
                // Tambah ke favorit
                console.log('Menambah favorit:', jobId);
                const response = await api.post('/favorit', { id_lowongan: jobId });
                console.log('Post response:', response.data);
                setIsFavorited(true);
                alert('Ō£© Lowongan berhasil disimpan ke favorit!');
            }
        } catch (err) {
            console.error('Error toggling favorite:', err);
            console.error('Response status:', err.response?.status);
            console.error('Response data:', err.response?.data);

            if (err.response?.status === 401) {
                alert('ŌÜĀ’ĖÅ Sesi Anda habis. Silakan login kembali.');
                localStorage.removeItem('token');
                localStorage.removeItem('role');
                window.location.href = '/login';
            } else {
                const msg = err.response?.data?.message || err.message || 'Gagal memproses favorit';
                alert(`ŌØī ${msg}`);
            }
        } finally {
            setIsLoading(false);
        }
    };

    const buttonStyle = {
        display: 'flex',
        alignItems: 'center',
        gap: '8px',
        padding: '10px 16px',
        borderRadius: '10px',
        fontSize: '13px',
        fontWeight: '700',
        border: 'none',
        cursor: isLoading ? 'not-allowed' : 'pointer',
        transition: 'all 0.3s ease',
        background: isFavorited 
            ? (isDark ? '#062f17' : '#f0fdf4') 
            : (isDark ? '#1a1008' : '#fffaf5'),
        color: isFavorited 
            ? (isDark ? '#4ade80' : '#16a34a') 
            : (isDark ? '#ea580c' : '#ea580c'),
        border: `1px solid ${isFavorited 
            ? (isDark ? '#22c55e' : '#16a34a')
            : (isDark ? '#3d2514' : '#eaddd3')}`,
        width: '100%',
        justifyContent: 'center',
        opacity: isLoading ? 0.7 : 1
    };

    return (
        <button
            onClick={toggleFavorite}
            style={buttonStyle}
            disabled={isLoading}
            onMouseEnter={(e) => {
                if (!isLoading) {
                    e.currentTarget.style.transform = 'translateY(-2px)';
                }
            }}
            onMouseLeave={(e) => {
                if (!isLoading) {
                    e.currentTarget.style.transform = 'translateY(0)';
                }
            }}
        >
            {isLoading ? 'ŌÅ│...' : (
                <>
                    {isFavorited ? (
                        <>
                            <span>ŌŁÉ</span> Hapus dari Favorit
                        </>
                    ) : (
                        <>
                            <span>Ōśå</span> Tambah ke Favorit
                        </>
                    )}
                </>
            )}
        </button>
    );
};

export default FavoriteService;
